   362→ * @param messageId - Gmail message ID
   363→ * @param result - Classification result from pipeline
   364→ * @throws Error if messageId is invalid or database operation fails
   365→ */
   366→export async function saveClassificationResult(messageId: string, result: ClassificationResult): Promise<void> {
   367→  // Validate input
   368→  if (!messageId || typeof messageId !== 'string' || messageId.trim() === '') {
   369→    throw new Error('Message ID is required and must be a non-empty string');
   370→  }
   371→
   372→  const pool = getPool();
   373→  const startedAt = new Date();
   374→  const completedAt = new Date(startedAt.getTime() + result.processingDurationMs);
   375→
   376→  try {
   377→    // Begin transaction
   378→    await pool.query('BEGIN');
   379→
   380→    // 1. Insert classification_session
   381→    const sessionId = await insertClassificationSession(pool, messageId, result, startedAt, completedAt);
   382→
   383→    // 2. Insert classification_stage (single stage for minimal MVP)
   384→    const stageType = 'complete_pipeline';
   385→    const stageDurationMs = result.processingDurationMs;
   386→    const weightScore = {
   387→      selectedLabels: result.selectedLabels,
   388→      candidateScores: result.candidateScores,
   389→      selectionSummary: result.selectionSummary,
   390→    };
   391→    const rationale = extractFinalRationale(result.selectedLabels);
   392→
   393→    const stageId = await insertClassificationStage(
   394→      pool,
   395→      sessionId,
   396→      1, // stage_order
   397→      stageType,
   398→      stageDurationMs,
   399→      weightScore,
   400→      rationale
   401→    );
   402→
   403→    // 3. Insert stage_category_eval records for all candidates
   404→    if (Object.keys(result.candidateScores).length > 0) {
