   421→ * Rolls back entire batch if any individual result fails to persist.
   422→ *
   423→ * @param results - Map of message IDs to classification results
   424→ * @throws Error if batch is empty or any database operation fails
   425→ */
   426→export async function saveClassificationBatch(results: Map<string, ClassificationResult>): Promise<void> {
   427→  // Validate input
   428→  if (results.size === 0) {
