   430→  }
   431→
   432→  const pool = getPool();
   433→
   434→  try {
   435→    // Begin transaction
   436→    await pool.query('BEGIN');
   437→
   438→    // Process each result in batch
   439→    for (const [messageId, result] of Array.from(results.entries())) {
   440→      const startedAt = new Date();
   441→      const completedAt = new Date(startedAt.getTime() + result.processingDurationMs);
   442→
   443→      // 1. Insert classification_session
   444→      const sessionId = await insertClassificationSession(pool, messageId, result, startedAt, completedAt);
   445→
   446→      // 2. Insert classification_stage
   447→      const stageType = 'complete_pipeline';
   448→      const stageDurationMs = result.processingDurationMs;
   449→      const weightScore = {
   450→        selectedLabels: result.selectedLabels,
   451→        candidateScores: result.candidateScores,
   452→        selectionSummary: result.selectionSummary,
   453→      };
   454→      const rationale = extractFinalRationale(result.selectedLabels);
   455→
   456→      const stageId = await insertClassificationStage(
   457→        pool,
   458→        sessionId,
   459→        1,
   460→        stageType,
   461→        stageDurationMs,
   462→        weightScore,
   463→        rationale
   464→      );
   465→
   466→      // 3. Insert stage_category_eval records
   467→      if (Object.keys(result.candidateScores).length > 0) {
   468→        await insertStageCategoryEvals(pool, stageId, result.candidateScores);
   469→      }
   470→    }
   471→
   472→    // Commit transaction
   473→    await pool.query('COMMIT');
   474→  } catch (error) {
   475→    // Rollback on error
   476→    await pool.query('ROLLBACK');
   477→    throw new Error(`Failed to save classification batch: ${(error as Error).message}`);
   478→  }
   479→}
