   472→  private async compileConfigurationRules(config: CategoryConfiguration): Promise<CompiledRule[]> {
   473→    const startTime = Date.now();
   474→    const compiledRules: CompiledRule[] = [];
   475→
   476→    for (const [categoryName, category] of Object.entries(config.processing_config.top_level_categories)) {
   477→      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
   478→        if (subtype.rule_based_classification) {
   479→          for (const [tier, rules] of Object.entries(subtype.rule_based_classification)) {
   480→            if (rules) {
   481→              for (const rule of rules) {
   482→                try {
   483→                  let pattern: RegExp;
   484→
   485→                  switch (rule.operation) {
   486→                  case 'contains_any':
   487→                    pattern = new RegExp(
   488→                      rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '',
   489→                      'i'
   490→                    );
   491→                    break;
   492→                  case 'starts_with':
   493→                    pattern = new RegExp(
   494→                      '^(' +
   495→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
   496→                          ')',
   497→                      'i'
   498→                    );
   499→                    break;
   500→                  case 'ends_with':
   501→                    pattern = new RegExp(
   502→                      '(' +
   503→                          (rule.values?.map((v) => v.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')).join('|') || '') +
   504→                          ')$',
   505→                      'i'
   506→                    );
   507→                    break;
   508→                  case 'regex_any':
   509→                    pattern = new RegExp(rule.values?.join('|') || '', 'i');
   510→                    break;
   511→                  default:
   512→                    continue; // Skip unknown operations
   513→                  }
   514→
   515→                  compiledRules.push({
   516→                    category: categoryName,
   517→                    subtype: subtypeName,
   518→                    tier: tier as 'high' | 'medium' | 'low',
   519→                    pattern,
   520→                    weight: rule.weight,
   521→                    parallel_safe: true, // Assume parallel safe unless marked otherwise
   522→                  });
   523→                } catch (error) {
   524→                  console.warn(`Failed to compile rule for ${categoryName}.${subtypeName}.${tier}:`, error);
   525→                }
   526→              }
   527→            }
   528→          }
   529→        }
   530→      }
   531→    }
   532→
   533→    // Update performance metrics
   534→    if (!config.performanceMetrics) {
   535→      config.performanceMetrics = {};
   536→    }
   537→    config.performanceMetrics.rule_compilation_time_ms = Date.now() - startTime;
   538→    config.performanceMetrics.total_rules = compiledRules.length;
   539→    config.performanceMetrics.parallel_compatible_rules = compiledRules.filter((r) => r.parallel_safe).length;
   540→
   541→    return compiledRules;
   542→  }
