   698→
   699→      for (const domain of domains) {
   700→        if (typeof domain !== 'string') {
   701→          errors.push(`Domain group ${groupName} contains non-string domain: ${domain}`);
   702→        } else if (!/^[a-zA-Z0-9.-]+\\.[a-zA-Z]{2,}$/.test(domain)) {
