      // Mock ClassificationPipeline to throw error
      jest.spyOn(ClassificationPipeline.prototype, 'classify').mockRejectedValue(new Error('Classification failed'));

      const { processSingleEmail } = await import('../../src/cli/test-pipeline');

      const summary = await processSingleEmail('msg-003', mockProcessingConfig, false);

      expect(summary.success).toBe(0);
      expect(summary.errors).toBe(1);
    });
  });

