#!/usr/bin/env node
/**
 * End-to-End Testing CLI Tool (T036k)
 *
 * Simple CLI for manual end-to-end testing of classification pipeline.
 * Supports single email, batch, and date-range processing modes.
 *
 * Usage:
 *   npm run test:pipeline -- --mode single --message-id <id>
 *   npm run test:pipeline -- --mode batch --limit 10
 *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
 *   npm run test:pipeline -- --dry-run  # Classify without persisting
 *
 * Output:
 *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
 *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
 *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
 */

import { promises as fs } from 'fs';
import { join } from 'path';
import {
  fetchEmailById,
  fetchUnclassifiedEmails,
  fetchEmailsByDateRange,
  closePool as closeQueryPool,
} from '../persistence/email-query';
import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
import { ClassificationPipeline } from '../../../classification-engine/src/pipeline/classification-pipeline';
import { ConfigurationLoader } from '../../../classification-engine/src/config/config-loader';
import type {
  ProcessingConfig,
  CategoryConfiguration,
} from '../../../classification-engine/src/types/category-configuration';
import type { EmailMessage } from '../../../classification-engine/src/types/email-message';
import type { ClassificationResult } from '../../../classification-engine/src/types/classification-result';

/**
 * CLI argument structure
 */
export interface CLIArguments {
  mode: 'single' | 'batch' | 'date-range';
  messageId?: string;
  limit?: number;
  startDate?: string;
  endDate?: string;
  dryRun: boolean;
}

/**
 * Processing summary statistics
 */
export interface ProcessingSummary {
  totalEmails: number;
  success: number;
  errors: number;
  totalDurationMs: number;
  errorDetails: Array<{ messageId: string; error: string }>;
}

/**
 * Parse command line arguments
 *
 * @param args - Process arguments (excluding node and script path)
 * @returns Parsed CLI arguments
 * @throws Error if required arguments missing or invalid
 */
export function parseArguments(args: string[]): CLIArguments {
  const result: Partial<CLIArguments> = {
    dryRun: false,
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];

    switch (arg) {
    case '--mode':
      result.mode = args[++i] as 'single' | 'batch' | 'date-range';
      break;
    case '--message-id':
      result.messageId = args[++i];
      break;
    case '--limit':
      result.limit = parseInt(args[++i], 10);
      break;
    case '--start':
      result.startDate = args[++i];
      break;
    case '--end':
      result.endDate = args[++i];
      break;
    case '--dry-run':
      result.dryRun = true;
      break;
    }
  }

  // Validate required arguments
  if (!result.mode) {
    throw new Error('Mode is required (--mode single|batch|date-range)');
  }

  if (!['single', 'batch', 'date-range'].includes(result.mode)) {
    throw new Error('Invalid mode. Must be: single, batch, or date-range');
  }

  if (result.mode === 'single' && !result.messageId) {
    throw new Error('message-id is required for single mode (--message-id <id>)');
  }

  if (result.mode === 'date-range') {
    if (!result.startDate || !result.endDate) {
      throw new Error(
        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
      );
    }
  }

  return result as CLIArguments;
}

/**
 * Load configuration from config directory
 *
 * @returns Loaded processing configuration
 * @throws Error if configuration loading fails
 */
async function loadConfiguration(): Promise<ProcessingConfig> {
  const configLoader = new ConfigurationLoader({
    configDir: join(process.cwd(), 'config'),
    enableHotReload: false,
    validateOnLoad: true,
  });

  const categoryConfigResult = await configLoader.loadCategoryConfiguration();

  if (!categoryConfigResult.validationPassed) {
    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
  }

  // Return the complete processing_config which includes all required fields
  return categoryConfigResult.config.processing_config;
}

/**
 * Process single email through classification pipeline
 *
 * @param messageId - Gmail message ID
 * @param config - Processing configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processSingleEmail(
  messageId: string,
  config: ProcessingConfig,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 1,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // 1. Fetch email from database
    console.log(`Fetching email: ${messageId}`);
    const email = await fetchEmailById(messageId);

    // 2. Initialize pipeline
    const pipeline = new ClassificationPipeline(config);

    // 3. Classify email
    console.log(`Classifying: [${email.id}] ${email.subject}`);
    const result = await pipeline.classify(email);

    // 4. Output result
    console.log(formatEmailOutput(email, result));

    // 5. Persist result (unless dry-run)
    if (!dryRun) {
      await saveClassificationResult(messageId, result);
      console.log(`Persisted classification result for ${messageId}`);
    } else {
      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
    }

    // 6. Write explainability trace
    const tracePath = await writeExplainabilityTrace(email, result);
    console.log(`Explainability trace: ${tracePath}`);

    summary.success = 1;
    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    summary.errors = 1;
    summary.totalDurationMs = Date.now() - startTime;
    summary.errorDetails.push({
      messageId,
      error: error instanceof Error ? error.message : String(error),
    });

    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
  }

  return summary;
}

/**
 * Process batch of unclassified emails
 *
 * @param limit - Maximum number of emails to process
 * @param config - Processing configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processBatchEmails(
  limit: number,
  config: ProcessingConfig,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // 1. Fetch unclassified emails
    console.log(`Fetching up to ${limit} unclassified emails...`);
    const emails = await fetchUnclassifiedEmails(limit);

    summary.totalEmails = emails.length;
    console.log(`Found ${emails.length} emails to process\n`);

    if (emails.length === 0) {
      console.log('No unclassified emails found.');
      summary.totalDurationMs = Date.now() - startTime;
      return summary;
    }

    // 2. Initialize pipeline
    const pipeline = new ClassificationPipeline(config);

    // 3. Process each email
    for (const email of emails) {
      const emailStartTime = Date.now();

      try {
        console.log(`Classifying [${email.id}] ${email.subject}`);
        const result = await pipeline.classify(email);

        console.log(formatEmailOutput(email, result));

        if (!dryRun) {
          await saveClassificationResult(email.id, result);
        }

        await writeExplainabilityTrace(email, result);

        summary.success++;
      } catch (error) {
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Process emails within date range
 *
 * @param startDate - Start date (YYYY-MM-DD)
 * @param endDate - End date (YYYY-MM-DD)
 * @param limit - Maximum number of emails to process
 * @param config - Processing configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processDateRangeEmails(
  startDate: string,
  endDate: string,
  limit: number,
  config: ProcessingConfig,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // Parse and validate dates
    const start = new Date(startDate);
    const end = new Date(endDate);

    if (start > end) {
      throw new Error('Invalid date range: start date must be before end date');
    }

    // 1. Fetch emails by date range
    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
    const emails = await fetchEmailsByDateRange(start, end, limit);

    summary.totalEmails = emails.length;
    console.log(`Found ${emails.length} emails to process\n`);

    if (emails.length === 0) {
      console.log('No emails found in date range.');
      summary.totalDurationMs = Date.now() - startTime;
      return summary;
    }

    // 2. Initialize pipeline
    const pipeline = new ClassificationPipeline(config);

    // 3. Process each email
    for (const email of emails) {
      try {
        console.log(`Classifying [${email.id}] ${email.subject}`);
        const result = await pipeline.classify(email);

        console.log(formatEmailOutput(email, result));

        if (!dryRun) {
          await saveClassificationResult(email.id, result);
        }

        await writeExplainabilityTrace(email, result);

        summary.success++;
      } catch (error) {
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Format per-email output line
 *
 * @param email - Email message
 * @param result - Classification result
 * @returns Formatted output string
 */
export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
  const labels = result.selectedLabels.map((label) => label.subtype || label.category).join(', ');
  const primaryLabel = result.selectedLabels.find((l) => l.isPrimary);
  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
  const durationSec = (result.processingDurationMs / 1000).toFixed(1);

  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
}

/**
 * Format summary statistics
 *
 * @param summary - Processing summary
 * @returns Formatted summary string
 */
export function formatSummary(summary: ProcessingSummary): string {
  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';

  let output = `\n${'='.repeat(80)}\n`;
  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
  output += `${summary.success} success, ${summary.errors} errors\n`;

  if (summary.errorDetails.length > 0) {
    output += '\nErrors:\n';
    for (const error of summary.errorDetails) {
      output += `  - [${error.messageId}] ${error.error}\n`;
    }
  }

  output += `${'='.repeat(80)}\n`;

  return output;
}

/**
 * Write explainability trace to file
 *
 * @param email - Email message
 * @param result - Classification result
 * @returns Path to written trace file
 */
export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
  // Create timestamped output directory
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').split('.')[0].replace('T', '-');
  const outputDir = join(process.cwd(), 'test-pipeline-results', timestamp);

  await fs.mkdir(outputDir, { recursive: true });

  // Write trace JSON
  const tracePath = join(outputDir, `${email.id}.json`);
  const trace = {
    messageId: email.id,
    subject: email.subject,
    from: email.from.email,
    date: email.date,
    classificationResult: result,
    timestamp: new Date().toISOString(),
  };

  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));

  return tracePath;
}

/**
 * Main CLI entry point
 *
 * @param args - Command line arguments
 * @returns Exit code (0 = success, 1 = error)
 */
export async function runTestPipeline(args: string[]): Promise<number> {
  try {
    // 1. Parse arguments
    const cliArgs = parseArguments(args);

    console.log(`\nTest Pipeline - Mode: ${cliArgs.mode}${cliArgs.dryRun ? ' [DRY RUN]' : ''}\n`);

    // 2. Load configuration
    console.log('Loading configuration...');
    const config = await loadConfiguration();
    console.log('Configuration loaded successfully\n');

    // 3. Process based on mode
    let summary: ProcessingSummary;

    switch (cliArgs.mode) {
    case 'single':
      summary = await processSingleEmail(cliArgs.messageId!, config, cliArgs.dryRun);
      break;

    case 'batch':
      summary = await processBatchEmails(cliArgs.limit || 10, config, cliArgs.dryRun);
      break;

    case 'date-range':
      summary = await processDateRangeEmails(
          cliArgs.startDate!,
          cliArgs.endDate!,
          cliArgs.limit || 100,
          config,
          cliArgs.dryRun
      );
      break;
    }

    // 4. Print summary
    console.log(formatSummary(summary));

    // 5. Cleanup
    await closeQueryPool();
    await closeWriterPool();

    // 6. Return exit code
    return summary.errors > 0 ? 1 : 0;
  } catch (error) {
    console.error(`\nFatal error: ${error instanceof Error ? error.message : String(error)}`);

    // Cleanup on error
    try {
      await closeQueryPool();
      await closeWriterPool();
    } catch {
      // Ignore cleanup errors
    }

    return 1;
  }
}

/**
 * CLI execution (only when run directly)
 */
if (require.main === module) {
