/**
 * Mock ProcessingConfig for pipeline initialization
 */
const mockProcessingConfig: ProcessingConfig = {
  version: 2,
  taxonomy_notes: 'Test taxonomy',
  confidence_thresholds: {
    high_confidence: 0.8,
    medium_confidence: 0.5,
    low_confidence: 0.3,
    secondary_label_min_gap: 0.15,
  },
