      expect(() => parseArguments(['--mode', 'single'])).toThrow('message-id is required for single mode');
    });

    test('should require start and end dates for date-range mode', async () => {
      const { parseArguments } = await import('../../src/cli/test-pipeline');

      expect(() => parseArguments(['--mode', 'date-range', '--start', '2025-09-01'])).toThrow(
        'Both start and end dates are required'
      );
    });

